// ZoneEdge is the edge representation of Zone.
type ZoneEdge struct {
	Node   *Zone  `json:"node"`
	Cursor Cursor `json:"cursor"`
}

// ZoneConnection is the connection containing edges to Zone.
type ZoneConnection struct {
	Edges      []*ZoneEdge `json:"edges"`
	PageInfo   PageInfo    `json:"pageInfo"`
	TotalCount int         `json:"totalCount"`
}

func (c *ZoneConnection) build(nodes []*Zone, pager *zonePager, after *Cursor, first *int, before *Cursor, last *int) {
	c.PageInfo.HasNextPage = before != nil
	c.PageInfo.HasPreviousPage = after != nil
	if first != nil && *first+1 == len(nodes) {
		c.PageInfo.HasNextPage = true
		nodes = nodes[:len(nodes)-1]
	} else if last != nil && *last+1 == len(nodes) {
		c.PageInfo.HasPreviousPage = true
		nodes = nodes[:len(nodes)-1]
	}
	var nodeAt func(int) *Zone
	if last != nil {
		n := len(nodes) - 1
		nodeAt = func(i int) *Zone {
			return nodes[n-i]
		}
	} else {
		nodeAt = func(i int) *Zone {
			return nodes[i]
		}
	}
	c.Edges = make([]*ZoneEdge, len(nodes))
	for i := range nodes {
		node := nodeAt(i)
		c.Edges[i] = &ZoneEdge{
			Node:   node,
			Cursor: pager.toCursor(node),
		}
	}
	if l := len(c.Edges); l > 0 {
		c.PageInfo.StartCursor = &c.Edges[0].Cursor
		c.PageInfo.EndCursor = &c.Edges[l-1].Cursor
	}
	if c.TotalCount == 0 {
		c.TotalCount = len(nodes)
	}
}

